Okay, so `createSelector` is just function composition with memoization,
like (simplified)

```js
function createSelector(dep1, dep2, dep3, fn) {
  const memo = new Map();
  return function selector(store) {
    if (!memo.has(store)) {
      const val1 = dep1(store);
      const val2 = dep2(store);
      const val3 = dep3(store);
      const result = fn(val1, val2, val3);
      memo.set(store, result);
    }
    return memo.get(store);
  };
}
```

